proof fn phi_2_interp_of_entry_between_no_alignment_guard(d: Directory, i: nat, va: nat, pte: PTE)
    requires
        d.inv(),
        i < d.entries.len(),
        d.interp_of_entry(i).contains_pair(va, pte),
    ensures
        va + pte.frame.size <= d.next_entry_base(i),
{
    d.lemma_interp_of_entry_between(i, va, pte);
}

